'use client';

import * as React from 'react';
import {
  Box,
  Button,
  Typography,
  IconButton,
  Stack,
  TextField,
} from '@mui/material';
import {
  DataGrid,
  GridColDef,
  GridToolbarContainer,
} from '@mui/x-data-grid';
import RefreshIcon from '@mui/icons-material/Refresh';
import AddIcon from '@mui/icons-material/Add';
import EditIcon from '@mui/icons-material/Edit';
import DeleteIcon from '@mui/icons-material/Delete';
import ViewColumnIcon from '@mui/icons-material/ViewColumn';
import FilterListIcon from '@mui/icons-material/FilterList';
import SearchIcon from '@mui/icons-material/Search';

interface Employee {
  id: number;
  name: string;
  age: number;
  joinDate: string;
  department: string;
  fullTime: boolean;
}

const rows: Employee[] = [
  { id: 1, name: 'Edward Perry', age: 25, joinDate: '2025-07-16', department: 'Finance', fullTime: true },
  { id: 2, name: 'Josephine Drake', age: 36, joinDate: '2025-07-16', department: 'Market', fullTime: false },
  { id: 3, name: 'Cody Phillips', age: 19, joinDate: '2025-07-16', department: 'Development', fullTime: true },
];

export default function EmployeesPage() {
  const [loading, setLoading] = React.useState(false);
  const [search, setSearch] = React.useState('');

  const columns: GridColDef[] = [
    { field: 'id', headerName: 'ID', width: 70 },
    { field: 'name', headerName: 'Name', flex: 1 },
    { field: 'age', headerName: 'Age', width: 100 },
    { field: 'joinDate', headerName: 'Join date', width: 150 },
    { field: 'department', headerName: 'Department', width: 180 },
    {
      field: 'fullTime',
      headerName: 'Full-time',
      width: 120,
      renderCell: (params) => (params.value ? '✔️' : '❌'),
    },
    {
      field: 'actions',
      headerName: '',
      width: 120,
      sortable: false,
      renderCell: () => (
        <Stack direction="row" spacing={1}>
          <IconButton size="small" color="primary">
            <EditIcon fontSize="small" />
          </IconButton>
          <IconButton size="small" color="error">
            <DeleteIcon fontSize="small" />
          </IconButton>
        </Stack>
      ),
    },
  ];

  // Custom Toolbar
  function CustomToolbar() {
    return (
      <GridToolbarContainer sx={{ justifyContent: 'space-between', p: 1 }}>
        <Stack direction="row" spacing={1}>
          <IconButton>
            <ViewColumnIcon />
          </IconButton>
          <IconButton>
            <FilterListIcon />
          </IconButton>
          <IconButton>
            <SearchIcon />
          </IconButton>
        </Stack>
      </GridToolbarContainer>
    );
  }

  // Filter rows by search
  const filteredRows = rows.filter(
    (row) =>
      row.name.toLowerCase().includes(search.toLowerCase()) ||
      row.department.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <Box sx={{ p: 4 }}>
      {/* Header */}
      <Typography variant="h6" fontWeight="bold" mb={2}>
        Employees
      </Typography>

      {/* Toolbar Top */}
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
        <TextField
          size="small"
          placeholder="Search..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          sx={{ width: 250 }}
        />
        <Stack direction="row" spacing={1}>
          <Button
            variant="outlined"
            startIcon={<RefreshIcon />}
            onClick={() => {
              setLoading(true);
              setTimeout(() => setLoading(false), 1000);
            }}
          >
            Refresh
          </Button>
          <Button variant="contained" startIcon={<AddIcon />}>
            Create
          </Button>
        </Stack>
      </Box>

      {/* DataGrid */}
      <Box
        sx={{
          height: 450,
          width: '100%',
          backgroundColor: 'white',
          borderRadius: 2,
          boxShadow: '0 4px 20px rgba(0,0,0,0.05)',
        }}
      >
        <DataGrid
          rows={filteredRows}
          columns={columns}
          pageSizeOptions={[5, 10]}
          initialState={{
            pagination: { paginationModel: { pageSize: 10, page: 0 } },
          }}
          disableRowSelectionOnClick
          loading={loading}
          slots={{
            toolbar: CustomToolbar,
          }}
        />
      </Box>
    </Box>
  );
}